patch:
--- a/comparator.sv
+++ b/comparator.sv
@@ -1,15 +1,15 @@
 module Comparator16bit (
   input [15:0] val_a,
   input [15:0] val_b,
   output reg equal,
   output reg greater
 );
   always @(*) begin
     equal = (val_a == val_b);
     greater = (val_a > val_b);
   end
 endmodule

 module testbench;
-  wire eq, gt;
-  Comparator16bit comp (.val_a(16'h1234), .val_b(8'h56), .equal(eq), .greater(gt));
+  wire eq, gt;
+  Comparator16bit comp (.val_a(16'h1234), .val_b(16'h0056), .equal(eq), .greater(gt));
 endmodule

before_code:
